/**
 * Lightweight client-side i18n. The brand display language is chosen by the
 * visitor (persisted to cookie + localStorage). Falls back to English for any
 * missing key. Translations are stored per-key (all locales together) for
 * maintainability.
 */

import { CATALOG } from "@/lib/catalog-i18n";

export type Locale = "en" | "zh" | "es" | "pt" | "ru" | "fil";

export interface LocaleMeta {
  code: Locale;
  label: string;
  english: string;
}

export const LOCALES: LocaleMeta[] = [
  { code: "en", label: "English (Global)", english: "English" },
  { code: "zh", label: "简体中文", english: "Chinese (Simplified)" },
  { code: "es", label: "Español", english: "Spanish" },
  { code: "pt", label: "Português", english: "Portuguese" },
  { code: "ru", label: "Русский", english: "Russian" },
  { code: "fil", label: "Filipino", english: "Filipino" },
];

export const LOCALE_CODES: Locale[] = LOCALES.map((l) => l.code);

export function isLocale(v: unknown): v is Locale {
  return typeof v === "string" && (LOCALE_CODES as string[]).includes(v);
}

type Entry = Record<Locale, string>;

